class Solution:
    def minCapability(self, nums, k):
        n = len(nums)
        def max_count(cap):
            dp_prev2 = 0
            dp_prev1 = 0
            for i in range(n):
                take = dp_prev2 + (1 if nums[i] <= cap else 0)
                skip = dp_prev1
                cur = max(take, skip)
                dp_prev2 = dp_prev1
                dp_prev1 = cur
            return dp_prev1
        lo, hi = min(nums), max(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if max_count(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

