class Solution:
    def minCapability(self, nums, k):
        def count_ge(cap):
            cnt = 0
            i = 0
            n = len(nums)
            while i < n:
                if nums[i] <= cap:
                    cnt += 1
                    i += 2
                else:
                    i += 1
            return cnt
        lo, hi = min(nums), max(nums)
        while lo < hi:
            mid = (lo + hi) // 2
            if count_ge(mid) >= k:
                hi = mid
            else:
                lo = mid + 1
        return lo

