var minCapability = function(nums, k) {
    const countGe = (cap) => {
        let cnt = 0;
        let i = 0;
        const n = nums.length;
        while (i < n) {
            if (nums[i] <= cap) {
                cnt++;
                i += 2;
            } else {
                i++;
            }
        }
        return cnt;
    };
    let lo = nums[0];
    let hi = nums[0];
    for (const x of nums) {
        if (x < lo) lo = x;
        if (x > hi) hi = x;
    }
    while (lo < hi) {
        const mid = lo + Math.floor((hi - lo) / 2);
        if (countGe(mid) >= k) {
            hi = mid;
        } else {
            lo = mid + 1;
        }
    }
    return lo;
};
